import React from "react";

// Lojistik şirketi iç sistemi için modern, FERAH (açık tema) ana sayfa
// Sıfır ek bağımlılık: sadece React + component içi CSS
// İsterseniz metrikleri props ile dışarıdan geçebilirsiniz; yoksa placeholder değerler görünür.

export default function AnaSayfa({
    kpi = {
        bugunTalep: 42,
        bekleyenTeslimat: 18,
        buAyGelir: 248000,
        buAyGider: 171500,
        tedarikciSayisi: 36,
    },
    onYeniGelir = () => alert("Yeni Gelir Ekle"),
    onYeniGider = () => alert("Yeni Gider Ekle"),
    onYeniTalep = () => alert("Yeni Talep Oluştur"),
    onYeniTedarik = () => alert("Yeni Tedarik Kaydı"),
}) {
    const net = kpi.buAyGelir - kpi.buAyGider;
    const netColor = net >= 0 ? "var(--green)" : "var(--red)";

    return (
        <div className="logi-root">
            <style>{`
        :root{
          --bg:#f7f8fb; --card:#ffffff; --text:#0f172a; --muted:#4b5563; --line:#e5e7eb;
          --brand:#2563eb; --brand-2:#1e40af; --yellow:#f59e0b; --green:#16a34a; --red:#ef4444; --indigo:#6366f1;
        }
        .logi-root{ background:var(--bg); color:var(--text); min-height:100dvh; }
        .container{ max-width:1200px; margin:0 auto; padding:20px; }
        .topbar{ position:sticky; top:0; z-index:10; backdrop-filter:saturate(1.1) blur(8px);
                 border-bottom:1px solid var(--line); background:rgba(255,255,255,.7); }
        .topbar-in{ display:flex; align-items:center; justify-content:space-between; gap:16px; padding:10px 20px; }
        .brand{ display:flex; align-items:center; gap:10px; font-weight:800; letter-spacing:.2px; }
        .brand-badge{ display:inline-flex; align-items:center; gap:6px; border:1px solid var(--line); background:#fff; padding:6px 10px; border-radius:999px; font-size:12px; }
        .dot{ width:8px; height:8px; border-radius:999px; background:var(--green); }
        .nav{ display:flex; gap:14px; flex-wrap:wrap; }
        .nav a{ text-decoration:none; color:#374151; padding:8px 10px; border-radius:10px; }
        .nav a:hover{ background:#eef2ff; color:var(--indigo); }

        .hero{ display:grid; grid-template-columns:1.2fr .8fr; gap:18px; margin:18px auto; }
        @media(max-width:960px){ .hero{ grid-template-columns:1fr; } }
        .panel{ background:var(--card); border:1px solid var(--line); border-radius:16px; box-shadow:0 6px 20px rgba(2,6,23,.04); }

        .hero-left{ padding:20px; }
        .title{ font-size:36px; line-height:1.1; font-weight:900; letter-spacing:-.02em; }
        .subtitle{ color:var(--muted); margin-top:8px; }
        .quick{ display:flex; flex-wrap:wrap; gap:10px; margin-top:14px; }
        .btn{ appearance:none; border:1px solid var(--line); background:#fff; padding:10px 14px; border-radius:12px; font-weight:600; cursor:pointer; }
        .btn.primary{ background:var(--brand); border-color:var(--brand); color:#fff; }
        .btn:hover{ transform:translateY(-1px); box-shadow:0 8px 18px rgba(37,99,235,.12); }

        .hero-right{ padding:16px; display:grid; place-items:center; }
        .placeholder{ width:100%; height:240px; border:2px dashed var(--line); border-radius:14px; display:grid; place-items:center; color:#6b7280; text-align:center; padding:12px; }

        .kpis{ display:grid; grid-template-columns:repeat(5,1fr); gap:12px; margin-top:12px; }
        @media(max-width:1200px){ .kpis{ grid-template-columns:repeat(3,1fr); } }
        @media(max-width:720px){ .kpis{ grid-template-columns:repeat(2,1fr); } }
        .kpi{ background:var(--card); border:1px solid var(--line); border-radius:14px; padding:14px; }
        .kpi h4{ font-size:12px; color:#6b7280; margin:0 0 6px; font-weight:600; }
        .kpi strong{ font-size:22px; }
        .trend{ font-size:12px; margin-left:6px; }

        .grid{ display:grid; grid-template-columns:1.1fr .9fr; gap:16px; margin-top:16px; }
        @media(max-width:1000px){ .grid{ grid-template-columns:1fr; } }
        .table{ width:100%; border-collapse:separate; border-spacing:0; }
        .table th, .table td{ padding:10px 12px; border-bottom:1px solid var(--line); text-align:left; font-size:14px; }
        .table thead th{ font-size:12px; color:#64748b; text-transform:uppercase; letter-spacing:.06em; background:#f8fafc; }
        .status{ padding:4px 8px; border-radius:999px; font-size:12px; border:1px solid var(--line); }
        .ok{ background:#ecfdf5; color:var(--green); border-color:#bbf7d0; }
        .warn{ background:#fff7ed; color:var(--yellow); border-color:#fed7aa; }
        .bad{ background:#fef2f2; color:var(--red); border-color:#fecaca; }

        .cta{ display:flex; justify-content:flex-end; gap:10px; margin-top:10px; }
      `}</style>

            {/* Topbar */}
            <div className="topbar">
                <div className="topbar-in container">
                    <div className="brand">{Logo()} Lojistik Portal</div>
                    <div className="nav" aria-label="primary">
                        <a href="#gelirgider">Gelir-Gider</a>
                        <a href="#talep">Talepler</a>
                        <a href="#tedarik">Tedarik</a>
                        <a href="#dashboard">Dashboard</a>
                    </div>
                    <div className="brand-badge"><span className="dot" /> Güncel</div>
                </div>
            </div>

            {/* Hero */}
            <main className="container">
                <section className="hero">
                    <div className="panel hero-left">
                        <h1 className="title">Operasyon Özetiniz</h1>
                        <p className="subtitle">Gelir–gider kayıtları, talep–tedarik akışı ve teslimatlar için hızlı bir başlangıç.</p>

                        <div className="quick" role="group" aria-label="Hızlı işlemler">
                            <button className="btn primary" onClick={onYeniGelir}>{Truck()} Yeni Gelir</button>
                            <button className="btn" onClick={onYeniGider}>{Bill()} Yeni Gider</button>
                            <button className="btn" onClick={onYeniTalep}>{Plus()} Talep Oluştur</button>
                            <button className="btn" onClick={onYeniTedarik}>{Box()} Tedarik Kaydı</button>
                        </div>

                        {/* KPIs */}
                        <div className="kpis">
                            <div className="kpi"><h4>Bugünkü Talepler</h4><strong>{kpi.bugunTalep}</strong></div>
                            <div className="kpi"><h4>Bekleyen Teslimat</h4><strong>{kpi.bekleyenTeslimat}</strong></div>
                            <div className="kpi"><h4>Bu Ay Gelir</h4><strong>{formatTL(kpi.buAyGelir)}</strong></div>
                            <div className="kpi"><h4>Bu Ay Gider</h4><strong>{formatTL(kpi.buAyGider)}</strong></div>
                            <div className="kpi"><h4>Net</h4><strong style={{ color: netColor }}>{formatTL(net)}</strong></div>
                        </div>
                    </div>

                    <div className="panel hero-right">
                        <div className="placeholder">
                            Buraya "Talep/Tedarik Dashboard" mini grafikleri, son 7 gün trendi veya bir harita yerleştirilebilir.
                        </div>
                    </div>
                </section>

                {/* Tablolar */}
                <section className="grid">
                    <div className="panel" id="gelirgider" style={{ padding: 16 }}>
                        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
                            <h3 style={{ margin: 0 }}>Son Gelir-Gider Hareketleri</h3>
                            <div className="cta">
                                <button className="btn" onClick={onYeniGelir}>{Plus()} Gelir</button>
                                <button className="btn" onClick={onYeniGider}>{Plus()} Gider</button>
                            </div>
                        </div>
                        <table className="table">
                            <thead>
                                <tr><th>Tarih</th><th>Tür</th><th>Açıklama</th><th>Tutar</th><th>Durum</th></tr>
                            </thead>
                            <tbody>
                                <tr><td>2025-09-01</td><td>Gelir</td><td>Taşıma Bedeli #INV-8421</td><td>{formatTL(18500)}</td><td><span className="status ok">Onaylandı</span></td></tr>
                                <tr><td>2025-09-01</td><td>Gider</td><td>Akaryakıt</td><td>{formatTL(6200)}</td><td><span className="status warn">Beklemede</span></td></tr>
                                <tr><td>2025-08-31</td><td>Gider</td><td>Depo Kirası</td><td>{formatTL(21000)}</td><td><span className="status ok">Ödendi</span></td></tr>
                            </tbody>
                        </table>
                    </div>

                    <div className="panel" id="talep" style={{ padding: 16 }}>
                        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
                            <h3 style={{ margin: 0 }}>Aktif Talepler / Tedarik</h3>
                            <a className="btn" href="#">Tüm Talepler</a>
                        </div>
                        <table className="table">
                            <thead>
                                <tr><th>Talep No</th><th>Müşteri</th><th>Çıkış → Varış</th><th>Kapasite</th><th>Durum</th></tr>
                            </thead>
                            <tbody>
                                <tr><td>REQ-1034</td><td>ABC A.Ş.</td><td>Gebze → İzmir</td><td>22 Palet</td><td><span className="status warn">Araç Aranıyor</span></td></tr>
                                <tr><td>REQ-1035</td><td>XYZ Lojistik</td><td>İstanbul → Ankara</td><td>12 Ton</td><td><span className="status ok">Planlandı</span></td></tr>
                                <tr><td>REQ-1036</td><td>Delta</td><td>Bursa → Adana</td><td>Full Truck</td><td><span className="status bad">İptal</span></td></tr>
                            </tbody>
                        </table>
                    </div>
                </section>
            </main>

            {/* Footer */}
            <footer className="container" style={{ color: '#6b7280', fontSize: 13, paddingBottom: 24 }}>
                © {new Date().getFullYear()} Lojistik Portal • Gizlilik • Şartlar • İletişim
            </footer>
        </div>
    );
}

// ---------------- Helpers ----------------
function formatTL(n) {
    try { return n.toLocaleString('tr-TR', { style: 'currency', currency: 'TRY' }); } catch { return `${n} ₺`; }
}

// ---------------- Icons (SVG, paket yok) ----------------
function Logo() {
    return (
        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#2563eb" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden>
            <rect x="3" y="3" width="18" height="18" rx="4" />
            <path d="M7 12h10M7 8h6M7 16h8" />
        </svg>
    );
}
function Truck() {
    return (
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginRight: 6 }}>
